/* The Pilot Lounge - Commercial Pilot question bank.
   Same schema as data/private.js: { id, acs, q, choices[], a (index of correct), src{doc, ref, url, quote} }.
   Facts and quotes trace to FAA public-domain references and the ACS (FAA-S-ACS-7B).
   To extend coverage, add objects to the questions array. */
window.PILOT_LOUNGE = window.PILOT_LOUNGE || {};
window.PILOT_LOUNGE.commercial = {
  "title": "Commercial Pilot",
  "acsDoc": "FAA-S-ACS-7B",
  "questions": [
    {"id":"ca-001","acs":"CA.I.A","q":"What is the minimum age to be eligible for a commercial pilot certificate?","choices":["16 years of age","18 years of age","17 years of age"],"a":1,"src":{"doc":"14 CFR 61.123","ref":"Eligibility requirements: General","url":"https://www.ecfr.gov/current/title-14/section-61.123","quote":"To be eligible for a commercial pilot certificate, a person must: (a) Be at least 18 years of age. (14 CFR 61.123(a))"}},
    {"id":"ca-002","acs":"CA.I.A","q":"Before applying for a commercial pilot certificate, an applicant must already hold which certificate?","choices":["A sport pilot certificate only","At least a private pilot certificate issued under Part 61, or meet the requirements of 61.73","No prior certificate is required"],"a":1,"src":{"doc":"14 CFR 61.123","ref":"Eligibility requirements: General","url":"https://www.ecfr.gov/current/title-14/section-61.123","quote":"Hold at least a private pilot certificate issued under this part or meet the requirements of 61.73. (14 CFR 61.123(h))"}},
    {"id":"ca-003","acs":"CA.I.A","q":"A commercial pilot may act as pilot in command of an aircraft carrying persons or property for compensation or hire under what condition?","choices":["Provided the person is qualified in accordance with Part 61 and the applicable parts of the chapter that apply to the operation","Only between sunrise and sunset","Only when carrying fewer than six passengers"],"a":0,"src":{"doc":"14 CFR 61.133","ref":"Commercial pilot privileges and limitations","url":"https://www.ecfr.gov/current/title-14/section-61.133","quote":"A person who holds a commercial pilot certificate may act as pilot in command of an aircraft Carrying persons or property for compensation or hire, provided the person is qualified in accordance with this part and with the applicable parts of this chapter that apply to the operation. (14 CFR 61.133(a)(1)(i))"}},
    {"id":"ca-004","acs":"CA.I.A","q":"A commercial pilot applicant for an airplane category rating who does not hold an instrument rating in the same category and class will have what limitation placed on the certificate?","choices":["A prohibition on all night flying","The carriage of passengers for hire in airplanes on cross-country flights in excess of 50 nautical miles or at night is prohibited","A prohibition on carrying any passengers"],"a":1,"src":{"doc":"14 CFR 61.133","ref":"Commercial pilot privileges and limitations","url":"https://www.ecfr.gov/current/title-14/section-61.133","quote":"A person who applies for a commercial pilot certificate with an airplane category or powered-lift category rating and does not hold an instrument rating in the same category and class will be issued a commercial pilot certificate that contains the limitation, \"The carriage of passengers for hire in (airplanes) (powered-lifts) on cross-country flights in excess of 50 nautical miles or at night is prohibited.\" (14 CFR 61.133(b)(1))"}},
    {"id":"ca-005","acs":"CA.I.A","q":"How is the cross-country limitation removed from a commercial airplane certificate issued without an instrument rating?","choices":["By satisfactorily accomplishing the requirements for an instrument rating in the same category and class","It cannot be removed and is permanent","By logging an additional 50 hours of cross-country time"],"a":0,"src":{"doc":"14 CFR 61.133","ref":"Commercial pilot privileges and limitations","url":"https://www.ecfr.gov/current/title-14/section-61.133","quote":"The limitation may be removed when the person satisfactorily accomplishes the requirements listed in 61.65 of this part for an instrument rating in the same category and class of aircraft listed on the person's commercial pilot certificate. (14 CFR 61.133(b)(1))"}},
    {"id":"ca-006","acs":"CA.I.A","q":"What is the minimum total flight time required for a commercial pilot certificate with an airplane single-engine class rating under Part 61?","choices":["100 hours","190 hours","250 hours"],"a":2,"src":{"doc":"14 CFR 61.129","ref":"Aeronautical experience","url":"https://www.ecfr.gov/current/title-14/section-61.129","quote":"A person who applies for a commercial pilot certificate with an airplane category and single-engine class rating must log at least 250 hours of flight time as a pilot. (14 CFR 61.129(a))"}},
    {"id":"ca-007","acs":"CA.I.A","q":"For a commercial single-engine airplane rating, the solo (or PIC with instructor aboard) requirements include one cross-country flight of what minimum total distance?","choices":["Not less than 300 nautical miles total distance with landings at a minimum of three points","Not less than 200 nautical miles total distance","Not less than 100 nautical miles total distance"],"a":0,"src":{"doc":"14 CFR 61.129","ref":"Aeronautical experience","url":"https://www.ecfr.gov/current/title-14/section-61.129","quote":"One cross-country flight of not less than 300 nautical miles total distance, with landings at a minimum of three points, one of which is a straight-line distance of at least 250 nautical miles from the original departure point. (14 CFR 61.129(a)(4)(i))"}},
    {"id":"ca-008","acs":"CA.I.A","q":"The commercial single-engine 5-hour night VFR solo requirement includes how many takeoffs and landings at an airport with an operating control tower?","choices":["20 takeoffs and 20 landings","10 takeoffs and 10 landings","5 takeoffs and 5 landings"],"a":1,"src":{"doc":"14 CFR 61.129","ref":"Aeronautical experience","url":"https://www.ecfr.gov/current/title-14/section-61.129","quote":"5 hours in night VFR conditions with 10 takeoffs and 10 landings (with each landing involving a flight in the traffic pattern) at an airport with an operating control tower. (14 CFR 61.129(a)(4)(ii))"}},
    {"id":"ca-009","acs":"CA.I.A","q":"The 20 hours of training for a commercial single-engine rating must include how many hours of training in a complex airplane, a turbine-powered airplane, or a technically advanced airplane (TAA)?","choices":["20 hours","10 hours","3 hours"],"a":1,"src":{"doc":"14 CFR 61.129","ref":"Aeronautical experience","url":"https://www.ecfr.gov/current/title-14/section-61.129","quote":"10 hours of training in a complex airplane, a turbine-powered airplane, or a technically advanced airplane (TAA) that meets the requirements of paragraph (j) of this section, or any combination thereof. (14 CFR 61.129(a)(3)(ii))"}},
    {"id":"ca-010","acs":"CA.I.A","q":"What minimum class of medical certificate must a pilot hold to exercise the privileges of a commercial pilot certificate in an airplane?","choices":["Third-class medical certificate","First-class medical certificate","At least a second-class medical certificate"],"a":2,"src":{"doc":"14 CFR 61.23","ref":"Medical certificates: Requirement and duration","url":"https://www.ecfr.gov/current/title-14/section-61.23","quote":"Must hold at least a second class medical certificate when exercising privileges of a commercial pilot certificate in an aircraft other than a balloon or glider. (14 CFR 61.23(a)(2)(ii))"}},
    {"id":"ca-011","acs":"CA.I.A","q":"A second-class medical certificate held for commercial pilot privileges expires at the end of the last day of which month after the date of examination?","choices":["The 24th month","The 12th month","The 6th month"],"a":1,"src":{"doc":"14 CFR 61.23","ref":"Medical certificates: Requirement and duration","url":"https://www.ecfr.gov/current/title-14/section-61.23","quote":"A second-class medical certificate ... a commercial pilot certificate ... [expires] 12th month after the month of the date of examination shown on the medical certificate. (14 CFR 61.23(d)(2)(i))"}},
    {"id":"ca-012","acs":"CA.I.B","q":"Under Part 61, a technically advanced airplane (TAA) must be equipped with which of the following installed components?","choices":["A retractable landing gear and a controllable pitch propeller","An electronic primary flight display, an electronic multifunction display with a moving map using GPS, and a two axis autopilot integrated with the navigation and heading guidance system","An engine of more than 200 horsepower"],"a":1,"src":{"doc":"14 CFR 61.129","ref":"Technically advanced airplane","url":"https://www.ecfr.gov/current/title-14/section-61.129","quote":"a technically advanced airplane must be equipped with an electronically advanced avionics system that includes the following installed components: (1) An electronic Primary Flight Display (PFD) ...; (2) An electronic Multifunction Display (MFD) that includes, at a minimum, a moving map using Global Positioning System (GPS) navigation ...; (3) A two axis autopilot integrated with the navigation and heading guidance system. (14 CFR 61.129(j))"}},
    {"id":"ca-013","acs":"CA.I.B","q":"Under 14 CFR 61.31, a high-performance airplane is defined as an airplane with what engine characteristic?","choices":["A turbine engine","Retractable landing gear, flaps, and a controllable pitch propeller","An engine of more than 200 horsepower"],"a":2,"src":{"doc":"14 CFR 61.31","ref":"Additional training required for operating high-performance airplanes","url":"https://www.ecfr.gov/current/title-14/section-61.31","quote":"no person may act as pilot in command of a high-performance airplane (an airplane with an engine of more than 200 horsepower). (14 CFR 61.31(f)(1))"}},
    {"id":"ca-014","acs":"CA.I.B","q":"To act as pilot in command of a high-performance airplane, a pilot generally must hold what documentation?","choices":["A one-time logbook endorsement from an authorized instructor certifying proficiency to operate a high-performance airplane","A second-class medical certificate","A type rating for that airplane"],"a":0,"src":{"doc":"14 CFR 61.31","ref":"Additional training required for operating high-performance airplanes","url":"https://www.ecfr.gov/current/title-14/section-61.31","quote":"Received a one-time endorsement in the pilot's logbook from an authorized instructor who certifies the person is proficient to operate a high-performance airplane. (14 CFR 61.31(f)(1)(ii))"}},
    {"id":"ca-015","acs":"CA.I.B","q":"For purposes of 14 CFR 61.31, the requirement for additional training to operate a pressurized aircraft capable of high-altitude operations applies to an aircraft that has a service ceiling or maximum operating altitude, whichever is lower, above what altitude?","choices":["18,000 feet MSL","Flight level 410","25,000 feet MSL"],"a":2,"src":{"doc":"14 CFR 61.31","ref":"Additional training required for operating pressurized aircraft capable of operating at high altitudes","url":"https://www.ecfr.gov/current/title-14/section-61.31","quote":"no person may act as pilot in command of a pressurized aircraft (an aircraft that has a service ceiling or maximum operating altitude, whichever is lower, above 25,000 feet MSL), unless that person has received and logged ground training from an authorized instructor. (14 CFR 61.31(g)(1))"}},
    {"id":"ca-016","acs":"CA.I.B","q":"To act as pilot in command of a complex airplane, a pilot must have received and logged training and obtained what endorsement?","choices":["A new biennial endorsement each 24 months","A type rating endorsement","A one-time endorsement in the pilot's logbook certifying proficiency to operate a complex airplane"],"a":2,"src":{"doc":"14 CFR 61.31","ref":"Additional training required for operating complex airplanes","url":"https://www.ecfr.gov/current/title-14/section-61.31","quote":"Received a one-time endorsement in the pilot's logbook from an authorized instructor who certifies the person is proficient to operate a complex airplane. (14 CFR 61.31(e)(1)(ii))"}},
    {"id":"ca-017","acs":"CA.I.B","q":"A person who acts as pilot in command of a turbojet-powered airplane must hold what for that aircraft?","choices":["A high-performance endorsement","A complex airplane endorsement","A type rating for that aircraft"],"a":2,"src":{"doc":"14 CFR 61.31","ref":"Type rating requirements","url":"https://www.ecfr.gov/current/title-14/section-61.31","quote":"A person who acts as a pilot in command of any of the following aircraft must hold a type rating for that aircraft: ... (2) Turbojet-powered airplanes. (14 CFR 61.31(a)(2))"}},
    {"id":"ca-018","acs":"CA.I.C","q":"For a flight not in the vicinity of an airport, what information must the pilot in command become familiar with before beginning the flight?","choices":["Weather reports and forecasts, fuel requirements, alternatives available if the planned flight cannot be completed, and any known traffic delays advised by ATC","Only the destination weather","Only the names of nearby airports"],"a":0,"src":{"doc":"14 CFR 91.103","ref":"Preflight action","url":"https://www.ecfr.gov/current/title-14/section-91.103","quote":"For a flight under IFR or a flight not in the vicinity of an airport, weather reports and forecasts, fuel requirements, alternatives available if the planned flight cannot be completed, and any known traffic delays of which the pilot in command has been advised by ATC. (14 CFR 91.103(a))"}},
    {"id":"ca-019","acs":"CA.I.C","q":"Before any flight, 14 CFR 91.103 requires the pilot in command to become familiar with which of the following?","choices":["Only the current NOTAMs for the departure airport","Runway lengths at airports of intended use and applicable takeoff and landing distance information","Only the forecast winds aloft"],"a":1,"src":{"doc":"14 CFR 91.103","ref":"Preflight action","url":"https://www.ecfr.gov/current/title-14/section-91.103","quote":"For any flight, runway lengths at airports of intended use, and the following takeoff and landing distance information. (14 CFR 91.103(b))"}},
    {"id":"ca-020","acs":"CA.I.E","q":"In Class E airspace at or above 10,000 feet MSL, what is the basic VFR flight visibility minimum?","choices":["3 statute miles","1 statute mile","5 statute miles"],"a":2,"src":{"doc":"14 CFR 91.155","ref":"Basic VFR weather minimums","url":"https://www.ecfr.gov/current/title-14/section-91.155","quote":"Class E: ... At or above 10,000 feet MSL [requires] 5 statute miles [flight visibility], 1,000 feet below, 1,000 feet above, 1 statute mile horizontal [distance from clouds]. (14 CFR 91.155(a))"}},
    {"id":"ca-021","acs":"CA.I.E","q":"What are the cloud clearance requirements for VFR flight in Class C airspace?","choices":["500 feet below, 1,000 feet above, and 2,000 feet horizontal","1,000 feet below, 1,000 feet above, and 1 statute mile horizontal","Clear of clouds"],"a":0,"src":{"doc":"14 CFR 91.155","ref":"Basic VFR weather minimums","url":"https://www.ecfr.gov/current/title-14/section-91.155","quote":"Class C [requires] 3 statute miles [flight visibility], 500 feet below, 1,000 feet above, 2,000 feet horizontal [distance from clouds]. (14 CFR 91.155(a))"}},
    {"id":"ca-022","acs":"CA.I.E","q":"What is the basic VFR weather minimum for flight visibility and distance from clouds in Class B airspace?","choices":["3 statute miles visibility and clear of clouds","1 statute mile visibility and clear of clouds","5 statute miles visibility and 1,000 feet below clouds"],"a":0,"src":{"doc":"14 CFR 91.155","ref":"Basic VFR weather minimums","url":"https://www.ecfr.gov/current/title-14/section-91.155","quote":"Class B [requires] 3 statute miles [flight visibility], Clear of Clouds. (14 CFR 91.155(a))"}},
    {"id":"ca-023","acs":"CA.I.F","q":"During the day under VFR conditions, an airplane must carry enough fuel to fly to the first point of intended landing and, assuming normal cruising speed, to fly after that for at least how long?","choices":["30 minutes","45 minutes","20 minutes"],"a":0,"src":{"doc":"14 CFR 91.151","ref":"Fuel requirements for flight in VFR conditions","url":"https://www.ecfr.gov/current/title-14/section-91.151","quote":"No person may begin a flight in an airplane under VFR conditions ... there is enough fuel to fly to the first point of intended landing and, assuming normal cruising speed During the day, to fly after that for at least 30 minutes. (14 CFR 91.151(a)(1))"}},
    {"id":"ca-024","acs":"CA.I.F","q":"At night under VFR conditions, an airplane must carry enough fuel to reach the first point of intended landing and then, at normal cruising speed, fly for at least how long?","choices":["45 minutes","60 minutes","30 minutes"],"a":0,"src":{"doc":"14 CFR 91.151","ref":"Fuel requirements for flight in VFR conditions","url":"https://www.ecfr.gov/current/title-14/section-91.151","quote":"At night, to fly after that for at least 45 minutes. (14 CFR 91.151(a)(2))"}},
    {"id":"ca-025","acs":"CA.I.H","q":"At cabin pressure altitudes above 14,000 feet MSL, the required minimum flight crew must be provided with and use supplemental oxygen during what portion of the flight?","choices":["Only during climb and descent","Only the portion exceeding 30 minutes","During the entire flight time at those altitudes"],"a":2,"src":{"doc":"14 CFR 91.211","ref":"Supplemental oxygen","url":"https://www.ecfr.gov/current/title-14/section-91.211","quote":"At cabin pressure altitudes above 14,000 feet (MSL) unless the required minimum flight crew is provided with and uses supplemental oxygen during the entire flight time at those altitudes. (14 CFR 91.211(a)(2))"}},
    {"id":"ca-026","acs":"CA.I.H","q":"Between cabin pressure altitudes above 12,500 feet MSL up to and including 14,000 feet MSL, the required minimum flight crew must use supplemental oxygen for that part of the flight that is of more than what duration?","choices":["More than 30 minutes duration","More than 15 minutes duration","More than 60 minutes duration"],"a":0,"src":{"doc":"14 CFR 91.211","ref":"Supplemental oxygen","url":"https://www.ecfr.gov/current/title-14/section-91.211","quote":"At cabin pressure altitudes above 12,500 feet (MSL) up to and including 14,000 feet (MSL) unless the required minimum flight crew is provided with and uses supplemental oxygen for that part of the flight at those altitudes that is of more than 30 minutes duration. (14 CFR 91.211(a)(1))"}},
    {"id":"ca-027","acs":"CA.I.H","q":"At cabin pressure altitudes above 15,000 feet MSL, the supplemental oxygen requirement is that:","choices":["Only the pilot in command must use oxygen","Each occupant of the aircraft must be provided with supplemental oxygen","Oxygen is required only above flight level 250"],"a":1,"src":{"doc":"14 CFR 91.211","ref":"Supplemental oxygen","url":"https://www.ecfr.gov/current/title-14/section-91.211","quote":"At cabin pressure altitudes above 15,000 feet (MSL) unless each occupant of the aircraft is provided with supplemental oxygen. (14 CFR 91.211(a)(3))"}},
    {"id":"ca-028","acs":"CA.I.H","q":"The required ground training for operating a pressurized aircraft capable of high-altitude operations must include which subject?","choices":["Multiengine performance planning","Aerobatic recovery techniques","Effects, symptoms, and causes of hypoxia and any other high-altitude sickness"],"a":2,"src":{"doc":"14 CFR 61.31","ref":"Additional training required for operating pressurized aircraft","url":"https://www.ecfr.gov/current/title-14/section-61.31","quote":"The ground training must include at least the following subjects: ... (iii) Effects, symptoms, and causes of hypoxia and any other high-altitude sickness. (14 CFR 61.31(g)(1)(iii))"}},
    {"id":"ca-029","acs":"CA.II.A","q":"Who is directly responsible for, and is the final authority as to, the operation of an aircraft?","choices":["The pilot in command","The aircraft owner","The air traffic controller"],"a":0,"src":{"doc":"14 CFR 91.3","ref":"Responsibility and authority of the pilot in command","url":"https://www.ecfr.gov/current/title-14/section-91.3","quote":"The pilot in command of an aircraft is directly responsible for, and is the final authority as to, the operation of that aircraft. (14 CFR 91.3(a))"}},
    {"id":"ca-030","acs":"CA.II.B","q":"During flight deck management, the commercial pilot should ensure that essential equipment, publications, and references are:","choices":["Left at the FBO to reduce weight","Stowed in the baggage compartment for the entire flight","Properly secured and readily available for use during the flight"],"a":2,"src":{"doc":"FAA-S-ACS-7B","ref":"Flight Deck Management (CA.II.B)","url":"https://www.faa.gov/training_testing/testing/acs","quote":"Flight Deck Management evaluates the applicant's ability to manage the resources available in the flight deck, including securing items and cargo and using all appropriate and available equipment. (FAA-S-ACS-7B, Area of Operation II, Task B)"}},
    {"id":"ca-031","acs":"CA.III.A","q":"A flashing white light signal directed at an aircraft taxiing on the airport surface means what?","choices":["Cleared to take off","Return to starting point on airport","Taxi clear of the runway in use"],"a":1,"src":{"doc":"AIM","ref":"Aeronautical Information Manual 4-3-13, Traffic Control Light Signals","url":"https://www.faa.gov/air_traffic/publications/atpubs/aim_html/chap4_section_3.html","quote":"Flashing white [to an aircraft on the ground means] Return to starting point on airport. (AIM 4-3-13)"}},
    {"id":"ca-032","acs":"CA.III.A","q":"A steady green light signal to an aircraft on the ground means what?","choices":["Stop","Cleared for takeoff","Cleared to taxi"],"a":1,"src":{"doc":"AIM","ref":"Aeronautical Information Manual 4-3-13, Traffic Control Light Signals","url":"https://www.faa.gov/air_traffic/publications/atpubs/aim_html/chap4_section_3.html","quote":"Steady green [to an aircraft on the ground means] Cleared for takeoff. (AIM 4-3-13)"}},
    {"id":"ca-033","acs":"CA.III.B","q":"Unless otherwise indicated, what direction are turns in a standard airport traffic pattern?","choices":["To the left","To the right","Either direction at pilot discretion"],"a":0,"src":{"doc":"14 CFR 91.126","ref":"Operating on or in the vicinity of an airport in Class G airspace","url":"https://www.ecfr.gov/current/title-14/section-91.126","quote":"When approaching to land at an airport without an operating control tower in Class G airspace ... Each pilot of an airplane must make all turns of that airplane to the left unless the airport displays approved light signals or visual markings indicating that turns should be made to the right. (14 CFR 91.126(b)(1))"}},
    {"id":"ca-034","acs":"CA.IV.A","q":"During a normal takeoff and climb, after lift-off the pilot should establish and maintain which airspeed unless otherwise specified?","choices":["The best angle-of-climb speed (Vx) at all times","The never-exceed speed (Vne)","The recommended climb airspeed such as Vy or the manufacturer's recommended value"],"a":2,"src":{"doc":"FAA-H-8083-3C","ref":"Airplane Flying Handbook, Takeoffs and Departure Climbs","url":"https://www.faa.gov/regulations_policies/handbooks_manuals/aviation/airplane_handbook","quote":"After lift-off, the pitch attitude should be adjusted and held to allow the airplane to accelerate to and maintain the recommended climb speed, such as VY, the best rate-of-climb speed. (FAA-H-8083-3C, Chapter 6)"}},
    {"id":"ca-035","acs":"CA.IV.E","q":"A short-field takeoff over a 50-foot obstacle is typically flown by establishing which climb speed after lift-off?","choices":["Cruise climb speed","The best angle-of-climb speed (Vx) until clear of the obstacle","The maneuvering speed (Va)"],"a":1,"src":{"doc":"FAA-H-8083-3C","ref":"Airplane Flying Handbook, Short-Field Takeoff and Maximum Performance Climb","url":"https://www.faa.gov/regulations_policies/handbooks_manuals/aviation/airplane_handbook","quote":"The short-field takeoff requires the use of the best angle-of-climb speed (VX) to clear an obstacle, then a transition to the best rate-of-climb speed (VY) once the obstacle is cleared. (FAA-H-8083-3C, Chapter 6)"}},
    {"id":"ca-036","acs":"CA.IV.M","q":"During the commercial power-off 180-degree accuracy approach and landing, the airplane should touch down within what distance relative to the specified point?","choices":["Within 50 feet before the specified point only","Within 500 feet beyond the specified point","Within 200 feet beyond the specified point"],"a":2,"src":{"doc":"FAA-S-ACS-7B","ref":"Power-Off 180 Accuracy Approach and Landing (CA.IV.M)","url":"https://www.faa.gov/training_testing/testing/acs","quote":"Touch down at a proper pitch attitude, within 200 feet beyond or on the specified point with no side drift, and with the airplane's longitudinal axis aligned with and over the runway center/landing path. (FAA-S-ACS-7B, Area of Operation IV, Task M)"}},
    {"id":"ca-037","acs":"CA.IV.M","q":"In a power-off 180-degree accuracy approach and landing, when should the power be reduced to idle to begin the maneuver?","choices":["On final approach after the runway is assured","Just before the flare","Abeam the intended landing point on the downwind leg"],"a":2,"src":{"doc":"FAA-S-ACS-7B","ref":"Power-Off 180 Accuracy Approach and Landing (CA.IV.M)","url":"https://www.faa.gov/training_testing/testing/acs","quote":"The power-off 180 accuracy approach and landing maneuver begins by reducing power to idle abeam the intended touchdown point on the downwind leg at a normal traffic pattern altitude. (FAA-S-ACS-7B, Area of Operation IV, Task M)"}},
    {"id":"ca-038","acs":"CA.IV.N","q":"When executing a go-around, the pilot's first action is generally to:","choices":["Lower the landing gear","Apply takeoff or maximum allowable power and establish a positive rate of climb","Retract the flaps fully and immediately"],"a":1,"src":{"doc":"FAA-H-8083-3C","ref":"Airplane Flying Handbook, Go-Around / Rejected Landing","url":"https://www.faa.gov/regulations_policies/handbooks_manuals/aviation/airplane_handbook","quote":"The first response after making the decision to go around is to apply takeoff or maximum allowable power and adjust the pitch attitude to slow or stop the descent. (FAA-H-8083-3C, Chapter 8)"}},
    {"id":"ca-039","acs":"CA.V.A","q":"For the commercial pilot, steep turns are performed using what bank angle?","choices":["A bank angle of 45 degrees","A bank angle of 30 degrees","A bank angle of 50 degrees"],"a":2,"src":{"doc":"FAA-S-ACS-7B","ref":"Steep Turns (CA.V.A)","url":"https://www.faa.gov/training_testing/testing/acs","quote":"The commercial pilot steep turn standard requires the applicant to establish the manufacturer's recommended airspeed or a safe airspeed not to exceed VA and a 50 degree bank. (FAA-S-ACS-7B, Area of Operation V, Task A)"}},
    {"id":"ca-040","acs":"CA.V.A","q":"As bank angle increases in a level turn, what happens to the load factor and the stall speed?","choices":["Both decrease","Load factor increases but stall speed decreases","Both increase"],"a":2,"src":{"doc":"FAA-H-8083-25C","ref":"Pilot's Handbook of Aeronautical Knowledge, Load Factors","url":"https://www.faa.gov/regulations_policies/handbooks_manuals/aviation/phak","quote":"As the bank angle increases, the load factor increases, and the stall speed increases. (FAA-H-8083-25C, Chapter 5)"}},
    {"id":"ca-041","acs":"CA.V.B","q":"A steep spiral is best described as which of the following?","choices":["A gliding turn around a surface-based reference point maintaining a constant radius, with the steepest bank not exceeding 60 degrees","A series of two opposing 180-degree climbing and descending turns","A maximum performance climbing turn"],"a":0,"src":{"doc":"FAA-H-8083-3C","ref":"Airplane Flying Handbook, Steep Spiral (Chapter 10)","url":"https://www.faa.gov/regulations_policies/handbooks_manuals/aviation/airplane_handbook","quote":"A steep spiral is a gliding turn wherein the pilot maintains a constant radius around a surface-based reference point ... the steepest bank should not exceed 60 degrees. (FAA-H-8083-3C, Chapter 10)"}},
    {"id":"ca-042","acs":"CA.V.C","q":"A chandelle is best described as which of the following?","choices":["A level 360-degree steep turn","A maximum performance, 180-degree climbing turn that concludes with the airplane in a wings-level, nose-high attitude just above stall speed","A constant-radius descending gliding turn"],"a":1,"src":{"doc":"FAA-H-8083-3C","ref":"Airplane Flying Handbook, Chandelle (Chapter 10)","url":"https://www.faa.gov/regulations_policies/handbooks_manuals/aviation/airplane_handbook","quote":"A chandelle is a maximum performance, 180 climbing turn that begins from approximately straight-and-level flight and concludes with the airplane in a wings-level, nose-high attitude just above stall speed. (FAA-H-8083-3C, Chapter 10)"}},
    {"id":"ca-043","acs":"CA.V.C","q":"At the completion of 180 degrees of turn in a chandelle, the airplane should be in what condition?","choices":["In a 50-degree bank at cruise airspeed","In a steep descent at Vne","Wings level, airspeed just above the power-on stall speed, with a nose-high pitch attitude held momentarily"],"a":2,"src":{"doc":"FAA-H-8083-3C","ref":"Airplane Flying Handbook, Chandelle (Chapter 10)","url":"https://www.faa.gov/regulations_policies/handbooks_manuals/aviation/airplane_handbook","quote":"At the completion of 180 of turn, the wings should be level to the horizon, the airspeed should be just above the power-on stall speed, and the airplane's pitch-high attitude should be held momentarily. (FAA-H-8083-3C, Chapter 10)"}},
    {"id":"ca-044","acs":"CA.V.D","q":"The lazy eight is notable because it is the only standard flight training maneuver in which:","choices":["Power remains at idle throughout","The airplane is inverted at the top","Flight control pressures are constantly changing"],"a":2,"src":{"doc":"FAA-H-8083-3C","ref":"Airplane Flying Handbook, Lazy Eights (Chapter 10)","url":"https://www.faa.gov/regulations_policies/handbooks_manuals/aviation/airplane_handbook","quote":"It is the only standard flight training maneuver in which flight control pressures are constantly changing. (FAA-H-8083-3C, Chapter 10)"}},
    {"id":"ca-045","acs":"CA.V.E","q":"In eights on pylons, the altitude that holds the visual reference line on the pylon is called what?","choices":["Density altitude","Absolute altitude","Pivotal altitude"],"a":2,"src":{"doc":"FAA-H-8083-3C","ref":"Airplane Flying Handbook, Eights On Pylons (Chapter 7)","url":"https://www.faa.gov/regulations_policies/handbooks_manuals/aviation/airplane_handbook","quote":"The altitude that is appropriate for eights on pylons is called the \"pivotal altitude\" and is determined by the airplane's groundspeed. (FAA-H-8083-3C, Chapter 7)"}},
    {"id":"ca-046","acs":"CA.V.E","q":"What is the rule-of-thumb method for estimating pivotal altitude when groundspeed is expressed in knots?","choices":["Square the groundspeed and divide by 11.3","Multiply the groundspeed by 11.3","Square the groundspeed and divide by 15"],"a":0,"src":{"doc":"FAA-H-8083-3C","ref":"Airplane Flying Handbook, Eights On Pylons (Chapter 7)","url":"https://www.faa.gov/regulations_policies/handbooks_manuals/aviation/airplane_handbook","quote":"a good rule of thumb for estimating the pivotal altitude is to square the groundspeed, then divide by 15 (if the groundspeed is in miles per hour) or divide by 11.3 (if the groundspeed is in knots), and then add the mean sea level (MSL) altitude of the ground reference. (FAA-H-8083-3C, Chapter 7)"}},
    {"id":"ca-047","acs":"CA.V.E","q":"In eights on pylons, if the projected visual reference line appears to move ahead of the pylon (the pylon appears to move back), the pilot should:","choices":["Increase altitude","Decrease altitude","Apply rudder to yaw the wing toward the pylon"],"a":0,"src":{"doc":"FAA-H-8083-3C","ref":"Airplane Flying Handbook, Eights On Pylons (Chapter 7)","url":"https://www.faa.gov/regulations_policies/handbooks_manuals/aviation/airplane_handbook","quote":"If the visual reference line appears to move ahead of the pylon (pylon appears to move back), the pilot should increase altitude. (FAA-H-8083-3C, Chapter 7)"}},
    {"id":"ca-048","acs":"CA.V.E","q":"How does pivotal altitude change with groundspeed?","choices":["It decreases as groundspeed increases","It is independent of groundspeed","It increases as groundspeed increases"],"a":2,"src":{"doc":"FAA-H-8083-3C","ref":"Airplane Flying Handbook, Eights On Pylons (Chapter 7)","url":"https://www.faa.gov/regulations_policies/handbooks_manuals/aviation/airplane_handbook","quote":"The pivotal altitude is the altitude at which, for a given groundspeed, the projection of the visual reference line to the pylon appears to pivot ... [estimated by squaring] the groundspeed. (FAA-H-8083-3C, Chapter 7)"}},
    {"id":"ca-049","acs":"CA.VI.A","q":"When using pilotage and dead reckoning, the pilot navigates primarily by:","choices":["Listening to automated weather broadcasts","Reference to landmarks and computed headings, groundspeed, and time","Following ATC radar vectors only"],"a":1,"src":{"doc":"FAA-H-8083-25C","ref":"Pilot's Handbook of Aeronautical Knowledge, Navigation","url":"https://www.faa.gov/regulations_policies/handbooks_manuals/aviation/phak","quote":"Pilotage is navigation by reference to landmarks or checkpoints. ... Dead reckoning is navigation solely by means of computations based on time, airspeed, distance, and direction. (FAA-H-8083-25C, Chapter 16)"}},
    {"id":"ca-050","acs":"CA.VI.C","q":"When a diversion to an alternate airport becomes necessary, the commercial pilot should first:","choices":["Establish a heading toward the alternate and estimate the new course, time, fuel, and distance","Descend immediately to pattern altitude","Continue to the original destination regardless"],"a":0,"src":{"doc":"FAA-H-8083-25C","ref":"Pilot's Handbook of Aeronautical Knowledge, Diversion","url":"https://www.faa.gov/regulations_policies/handbooks_manuals/aviation/phak","quote":"When the need to divert arises, the pilot should ... determine an estimate of the magnetic course to the alternate destination and the time and fuel required to reach it. (FAA-H-8083-25C, Chapter 16)"}},
    {"id":"ca-051","acs":"CA.VII.A","q":"While maneuvering during slow flight, the airplane is flown at an airspeed at which any further increase in angle of attack, load factor, or reduction in power would result in what?","choices":["A stall warning or onset of a stall","An increase in airspeed","An immediate stall"],"a":0,"src":{"doc":"FAA-S-ACS-7B","ref":"Maneuvering During Slow Flight (CA.VII.A)","url":"https://www.faa.gov/training_testing/testing/acs","quote":"Establish and maintain an airspeed at which any increase in angle of attack, increase in load factor, or reduction in power would result in a stall warning (e.g., aircraft buffet, stall horn, etc.). (FAA-S-ACS-7B, Area of Operation VII, Task A)"}},
    {"id":"ca-052","acs":"CA.VII.B","q":"During a power-off stall, recovery is initiated at the first indication of a stall by:","choices":["Increasing back pressure to hold altitude","Applying full opposite rudder only","Reducing the angle of attack, leveling the wings, and adjusting power as needed"],"a":2,"src":{"doc":"FAA-H-8083-3C","ref":"Airplane Flying Handbook, Approaches to Stalls and Stall Recovery","url":"https://www.faa.gov/regulations_policies/handbooks_manuals/aviation/airplane_handbook","quote":"The most important and immediate action in stall recovery is to reduce the angle of attack. (FAA-H-8083-3C, Chapter 4)"}},
    {"id":"ca-053","acs":"CA.VII.D","q":"An accelerated stall occurs when an airplane is stalled at:","choices":["An airspeed lower than the unaccelerated stall speed","Only while inverted","An airspeed higher than the normal 1G stall speed because of an increased load factor"],"a":2,"src":{"doc":"FAA-H-8083-3C","ref":"Airplane Flying Handbook, Accelerated Stalls","url":"https://www.faa.gov/regulations_policies/handbooks_manuals/aviation/airplane_handbook","quote":"Accelerated stalls can occur at higher-than-normal airspeeds due to abrupt or excessive control applications and may occur in steep turns, pull-ups, or other abrupt changes in flightpath. (FAA-H-8083-3C, Chapter 4)"}},
    {"id":"ca-054","acs":"CA.VII.E","q":"A spin will not occur unless which condition is present?","choices":["The airplane is stalled and there is a yawing moment","The flaps are fully extended","The airplane is at cruise airspeed"],"a":0,"src":{"doc":"FAA-H-8083-3C","ref":"Airplane Flying Handbook, Spin Awareness","url":"https://www.faa.gov/regulations_policies/handbooks_manuals/aviation/airplane_handbook","quote":"A stall must occur before a spin can occur. ... A spin occurs when the airplane is stalled and yaw is introduced. (FAA-H-8083-3C, Chapter 4)"}},
    {"id":"ca-055","acs":"CA.VIII.A","q":"Hypoxia caused by a reduced partial pressure of oxygen at altitude, with adequate oxygen reaching the lungs, is which type of hypoxia?","choices":["Hypoxic hypoxia","Hypemic hypoxia","Histotoxic hypoxia"],"a":0,"src":{"doc":"FAA-H-8083-25C","ref":"Pilot's Handbook of Aeronautical Knowledge, Hypoxia","url":"https://www.faa.gov/regulations_policies/handbooks_manuals/aviation/phak","quote":"Hypoxic hypoxia is a result of insufficient oxygen available to the body as a whole. A reduction in partial pressure of oxygen at high altitude is an example. (FAA-H-8083-25C, Chapter 17)"}},
    {"id":"ca-056","acs":"CA.VIII.A","q":"Above flight level 250, a pressurized aircraft must have at least how much additional supplemental oxygen available for each occupant in case of a loss of pressurization?","choices":["A 10-minute supply","A 2-hour supply","A 30-minute supply"],"a":0,"src":{"doc":"14 CFR 91.211","ref":"Supplemental oxygen, pressurized cabin aircraft","url":"https://www.ecfr.gov/current/title-14/section-91.211","quote":"At flight altitudes above flight level 250 unless at least a 10-minute supply of supplemental oxygen, in addition to any oxygen required to satisfy paragraph (a) of this section, is available for each occupant of the aircraft for use in the event that a descent is necessitated by loss of cabin pressurization. (14 CFR 91.211(b)(1)(i))"}},
    {"id":"ca-057","acs":"CA.VIII.B","q":"Above which flight level must one pilot at the controls wear and use an oxygen mask (subject to the two-pilot quick-donning exception below FL410)?","choices":["Flight level 250","Flight level 180","Flight level 350"],"a":2,"src":{"doc":"14 CFR 91.211","ref":"Supplemental oxygen, pressurized cabin aircraft","url":"https://www.ecfr.gov/current/title-14/section-91.211","quote":"At flight altitudes above flight level 350 unless one pilot at the controls of the airplane is wearing and using an oxygen mask that is secured and sealed. (14 CFR 91.211(b)(1)(ii))"}},
    {"id":"ca-058","acs":"CA.VIII.B","q":"The required ground training for operating a pressurized aircraft capable of high altitude must include knowledge of which of the following?","choices":["Duration of consciousness without supplemental oxygen","Seaplane operations","Aerobatic maneuvers"],"a":0,"src":{"doc":"14 CFR 61.31","ref":"Additional training required for operating pressurized aircraft","url":"https://www.ecfr.gov/current/title-14/section-61.31","quote":"The ground training must include at least the following subjects: ... (iv) Duration of consciousness without supplemental oxygen. (14 CFR 61.31(g)(1)(iv))"}},
    {"id":"ca-059","acs":"CA.IX.A","q":"The purpose of an emergency descent is to:","choices":["Descend the airplane as rapidly as possible, within structural and operating limits, to a lower altitude or to the ground","Maintain altitude while troubleshooting","Slow the airplane to its minimum controllable airspeed"],"a":0,"src":{"doc":"FAA-H-8083-3C","ref":"Airplane Flying Handbook, Emergency Descent","url":"https://www.faa.gov/regulations_policies/handbooks_manuals/aviation/airplane_handbook","quote":"An emergency descent is a maneuver for descending as rapidly as possible to a lower altitude or to the ground for an emergency landing. (FAA-H-8083-3C, Chapter 17)"}},
    {"id":"ca-060","acs":"CA.IX.B","q":"After an engine failure in a single-engine airplane, the pilot's first priority is to:","choices":["Declare an emergency before flying the airplane","Immediately attempt an engine restart before doing anything else","Establish the best glide airspeed and select a suitable landing area"],"a":2,"src":{"doc":"FAA-H-8083-3C","ref":"Airplane Flying Handbook, Emergency Approach and Landing","url":"https://www.faa.gov/regulations_policies/handbooks_manuals/aviation/airplane_handbook","quote":"When an engine failure occurs, the pilot's first responsibility is to fly the airplane and maintain a safe airspeed, which means establishing the best glide speed and selecting a suitable landing area. (FAA-H-8083-3C, Chapter 17)"}},
    {"id":"ca-061","acs":"CA.IX.B","q":"In an in-flight emergency requiring immediate action, the pilot in command may:","choices":["Deviate only with prior ATC approval in all cases","Never deviate from any regulation","Deviate from any rule of Part 91 to the extent required to meet that emergency"],"a":2,"src":{"doc":"14 CFR 91.3","ref":"Responsibility and authority of the pilot in command","url":"https://www.ecfr.gov/current/title-14/section-91.3","quote":"In an in-flight emergency requiring immediate action, the pilot in command may deviate from any rule of this part to the extent required to meet that emergency. (14 CFR 91.3(b))"}},
    {"id":"ca-062","acs":"CA.X.A","q":"On a conventional twin with both engines rotating clockwise as viewed from the pilot's seat, which is the critical engine?","choices":["Neither engine is critical","The left engine","The right engine"],"a":1,"src":{"doc":"FAA-H-8083-3C","ref":"Airplane Flying Handbook, Transition to Multiengine Airplanes (Chapter 13)","url":"https://www.faa.gov/regulations_policies/handbooks_manuals/aviation/airplane_handbook","quote":"The critical engine is the engine whose failure had the most adverse effect on directional control. On twins with each engine rotating in conventional, clockwise rotation as viewed from the pilot's seat, the critical engine will be the left engine. (FAA-H-8083-3C, Chapter 13)"}},
    {"id":"ca-063","acs":"CA.X.A","q":"On most multiengine airplane airspeed indicators, the blue radial line represents which speed?","choices":["The best rate of climb speed with one engine inoperative (Vyse)","The never-exceed speed (Vne)","The minimum control speed (Vmc)"],"a":0,"src":{"doc":"FAA-H-8083-3C","ref":"Airplane Flying Handbook, Transition to Multiengine Airplanes (Chapter 13)","url":"https://www.faa.gov/regulations_policies/handbooks_manuals/aviation/airplane_handbook","quote":"VYSE best rate of climb speed with OEI. Marked with a blue radial line on most airspeed indicators. (FAA-H-8083-3C, Chapter 13)"}},
    {"id":"ca-064","acs":"CA.X.B","q":"On most multiengine airplane airspeed indicators, the red radial line marks which speed?","choices":["Vy, the best rate of climb","Vyse, the single-engine best rate of climb","Vmc, the minimum control speed"],"a":2,"src":{"doc":"FAA-H-8083-3C","ref":"Airplane Flying Handbook, Transition to Multiengine Airplanes (Chapter 13)","url":"https://www.faa.gov/regulations_policies/handbooks_manuals/aviation/airplane_handbook","quote":"VMC is typically marked with a red radial line on most airspeed indicators. (FAA-H-8083-3C, Chapter 13)"}},
    {"id":"ca-065","acs":"CA.X.B","q":"What does the published minimum control speed (Vmc) for a multiengine airplane address?","choices":["Directional control only; there is no requirement that the airplane be able to climb at that airspeed","The minimum speed at which the airplane can climb on one engine","The maximum structural cruising speed"],"a":0,"src":{"doc":"FAA-H-8083-3C","ref":"Airplane Flying Handbook, Transition to Multiengine Airplanes (Chapter 13)","url":"https://www.faa.gov/regulations_policies/handbooks_manuals/aviation/airplane_handbook","quote":"There is no requirement under either determination that the airplane be capable of climbing at this airspeed. VMC only addresses directional control. (FAA-H-8083-3C, Chapter 13)"}},
    {"id":"ca-066","acs":"CA.X.B","q":"How does Vmc change as bank angle is reduced toward wings-level during single-engine flight?","choices":["Vmc decreases as bank angle decreases","Vmc increases as bank angle decreases","Vmc is unaffected by bank angle"],"a":1,"src":{"doc":"FAA-H-8083-3C","ref":"Airplane Flying Handbook, Transition to Multiengine Airplanes (Chapter 13)","url":"https://www.faa.gov/regulations_policies/handbooks_manuals/aviation/airplane_handbook","quote":"VMC increases as bank angle decreases. In fact, VMC may increase more than 3 knots for each degree of bank reduction between 5 and wings-level. (FAA-H-8083-3C, Chapter 13)"}},
    {"id":"ca-067","acs":"CA.X.A","q":"Multiengine airplanes are subject to P-factor. On a conventional twin, why does failure of the left engine produce the most asymmetrical thrust?","choices":["The right engine is mounted further forward","The descending propeller blade of the right engine is a greater distance from the center of gravity and has a longer moment arm","The left engine produces more power than the right"],"a":1,"src":{"doc":"FAA-H-8083-3C","ref":"Airplane Flying Handbook, Transition to Multiengine Airplanes (Chapter 13)","url":"https://www.faa.gov/regulations_policies/handbooks_manuals/aviation/airplane_handbook","quote":"The descending propeller blade of the right engine is also a greater distance from the center of gravity, and therefore has a longer moment arm than the descending propeller blade of the left engine. As a result, failure of the left engine will result in the most asymmetrical thrust. (FAA-H-8083-3C, Chapter 13)"}},
    {"id":"ca-068","acs":"CA.X.B","q":"How does Vmc change as power is increased on the operating engine?","choices":["Vmc is unchanged by power","Vmc decreases","Vmc increases as power is increased on the operating engine"],"a":2,"src":{"doc":"FAA-H-8083-3C","ref":"Airplane Flying Handbook, Transition to Multiengine Airplanes (Chapter 13)","url":"https://www.faa.gov/regulations_policies/handbooks_manuals/aviation/airplane_handbook","quote":"VMC increases as power is increased on the operating engine. With normally aspirated engines, VMC is highest at takeoff power. (FAA-H-8083-3C, Chapter 13)"}},
    {"id":"ca-069","acs":"CA.X.C","q":"In a multiengine airplane with an inoperative engine, why is a centered ball no longer the indicator of zero sideslip?","choices":["Because of asymmetric thrust, and there is no flight deck instrument that directly indicates conditions for zero sideslip","The ball always indicates zero sideslip regardless of engine condition","The turn coordinator fails with an engine out"],"a":0,"src":{"doc":"FAA-H-8083-3C","ref":"Airplane Flying Handbook, Transition to Multiengine Airplanes (Chapter 13)","url":"https://www.faa.gov/regulations_policies/handbooks_manuals/aviation/airplane_handbook","quote":"In a multiengine airplane with an inoperative engine, the centered ball is no longer the indicator of zero sideslip due to asymmetric thrust. In fact, there is no flight deck instrument that directly indicates conditions for zero sideslip. (FAA-H-8083-3C, Chapter 13)"}},
    {"id":"ca-070","acs":"CA.X.A","q":"Best one-engine-inoperative climb performance in a multiengine airplane is obtained at which speed?","choices":["Vyse with maximum available power and minimum drag","Va with the failed engine windmilling","Vmc with idle power"],"a":0,"src":{"doc":"FAA-H-8083-3C","ref":"Airplane Flying Handbook, Transition to Multiengine Airplanes (Chapter 13)","url":"https://www.faa.gov/regulations_policies/handbooks_manuals/aviation/airplane_handbook","quote":"Best OEI climb performance is obtained at VYSE with maximum available power and minimum drag. (FAA-H-8083-3C, Chapter 13)"}},
    {"id":"ca-071","acs":"CA.X.B","q":"How does Vmc change when the inoperative engine's propeller is windmilling at a low pitch, high rpm blade angle?","choices":["Vmc is unaffected by propeller drag","Vmc decreases","Vmc increases because of increased drag on the inoperative engine"],"a":2,"src":{"doc":"FAA-H-8083-3C","ref":"Airplane Flying Handbook, Transition to Multiengine Airplanes (Chapter 13)","url":"https://www.faa.gov/regulations_policies/handbooks_manuals/aviation/airplane_handbook","quote":"VMC increases with increased drag on the inoperative engine. VMC is highest, therefore, when the critical engine propeller is windmilling at the low pitch, high rpm blade angle. (FAA-H-8083-3C, Chapter 13)"}},
    {"id":"ca-072","acs":"CA.XI.A","q":"For a commercial single-engine rating, what minimum amount of solo (or PIC with instructor) flight time on the listed areas of operation is required?","choices":["Five hours","Twenty hours","Ten hours"],"a":2,"src":{"doc":"14 CFR 61.129","ref":"Aeronautical experience","url":"https://www.ecfr.gov/current/title-14/section-61.129","quote":"Ten hours of solo flight time in a single engine airplane or 10 hours of flight time performing the duties of pilot in command in a single engine airplane with an authorized instructor on board. (14 CFR 61.129(a)(4))"}},
    {"id":"ca-073","acs":"CA.XI.A","q":"After landing, securing the airplane includes which of the following actions?","choices":["Completing the after-landing and shutdown checklist and securing the airplane, including chocking or tying down as appropriate","Leaving the flight controls free to move in the wind","Leaving the master switch on to keep avionics cool"],"a":0,"src":{"doc":"FAA-S-ACS-7B","ref":"After Landing, Parking, and Securing (CA.XI.A)","url":"https://www.faa.gov/training_testing/testing/acs","quote":"Park in an appropriate area, considering the safety of nearby persons and property, and complete the appropriate checklist, then secure the airplane. (FAA-S-ACS-7B, Area of Operation XI, Task A)"}},
    {"id":"ca-074","acs":"CA.I.A","q":"For a commercial single-engine rating, the required 20 hours of training must include at least how many hours of instrument training using a view-limiting device?","choices":["10 hours","5 hours","3 hours"],"a":0,"src":{"doc":"14 CFR 61.129","ref":"Aeronautical experience","url":"https://www.ecfr.gov/current/title-14/section-61.129","quote":"Ten hours of instrument training using a view-limiting device including attitude instrument flying, partial panel skills, recovery from unusual flight attitudes, and intercepting and tracking navigational systems. (14 CFR 61.129(a)(3)(i))"}},
    {"id":"ca-075","acs":"CA.I.A","q":"What is the minimum total flight time required for a commercial pilot certificate with an airplane multiengine class rating under Part 61?","choices":["150 hours","190 hours","250 hours"],"a":2,"src":{"doc":"14 CFR 61.129","ref":"Aeronautical experience","url":"https://www.ecfr.gov/current/title-14/section-61.129","quote":"A person who applies for a commercial pilot certificate with an airplane category and multiengine class rating must log at least 250 hours of flight time as a pilot. (14 CFR 61.129(b))"}},
    {"id":"ca-076","acs":"CA.I.A","q":"Of the 100 hours in powered aircraft required for a commercial airplane single-engine rating, how many hours must be in airplanes?","choices":["25 hours","50 hours","100 hours"],"a":1,"src":{"doc":"14 CFR 61.129","ref":"Aeronautical experience","url":"https://www.ecfr.gov/current/title-14/section-61.129","quote":"100 hours in powered aircraft, of which 50 hours must be in airplanes. (14 CFR 61.129(a)(1))"}},
    {"id":"ca-077","acs":"CA.I.A","q":"The 100 hours of pilot-in-command time for a commercial single-engine rating must include at least how many hours in cross-country flight?","choices":["10 hours","100 hours","50 hours"],"a":2,"src":{"doc":"14 CFR 61.129","ref":"Aeronautical experience","url":"https://www.ecfr.gov/current/title-14/section-61.129","quote":"100 hours of pilot-in-command flight time, which includes at least 50 hours in cross-country flight of which at least 10 hours must be in airplanes. (14 CFR 61.129(a)(2))"}},
    {"id":"ca-078","acs":"CA.I.A","q":"A person authorized to operate an aircraft requiring a type rating without holding that type rating under 14 CFR 61.31(b) may do so for a period of up to how many days?","choices":["30 days","60 days","90 days"],"a":1,"src":{"doc":"14 CFR 61.31","ref":"Authorization in lieu of a type rating","url":"https://www.ecfr.gov/current/title-14/section-61.31","quote":"A person may be authorized to operate without a type rating for up to 60 days an aircraft requiring a type rating. (14 CFR 61.31(b))"}},
    {"id":"ca-079","acs":"CA.I.E","q":"For VFR flight in Class G airspace at night, more than 1,200 feet above the surface but less than 10,000 feet MSL, what is the minimum flight visibility for an airplane?","choices":["1 statute mile","5 statute miles","3 statute miles"],"a":2,"src":{"doc":"14 CFR 91.155","ref":"Basic VFR weather minimums","url":"https://www.ecfr.gov/current/title-14/section-91.155","quote":"Class G: ... More than 1,200 feet above the surface but less than 10,000 feet MSL ... Night [requires] 3 statute miles [flight visibility], 500 feet below, 1,000 feet above, 2,000 feet horizontal. (14 CFR 91.155(a))"}},
    {"id":"ca-080","acs":"CA.I.A","q":"A commercial pilot certificate applicant must be able to do which of the following with respect to the English language?","choices":["Read, speak, write, and understand the English language","Read English only","Speak English only"],"a":0,"src":{"doc":"14 CFR 61.123","ref":"Eligibility requirements: General","url":"https://www.ecfr.gov/current/title-14/section-61.123","quote":"Be able to read, speak, write, and understand the English language. (14 CFR 61.123(b))"}}
  ]
};
